#!/usr/bin/env node
/**
 * Reads wizard/dist/ and generates src/wizard-bundle.ts
 * The wizard HTML/CSS/JS is embedded as base64 Buffer literals so it works
 * inside a @yao-pkg/pkg binary without filesystem path issues.
 */
import fs from 'fs';
import path from 'path';
import { fileURLToPath } from 'url';

const __dirname = path.dirname(fileURLToPath(import.meta.url));
const WIZARD_DIST = path.join(__dirname, '..', 'wizard', 'dist');
const OUTPUT = path.join(__dirname, '..', 'src', 'wizard-bundle.ts');

if (!fs.existsSync(WIZARD_DIST)) {
  console.error('[generate-wizard-bundle] wizard/dist/ not found — run npm run build:wizard first');
  process.exit(1);
}

const files = {};

function addDir(dir, prefix = '') {
  for (const name of fs.readdirSync(dir)) {
    const full = path.join(dir, name);
    const key = prefix ? `${prefix}/${name}` : name;
    if (fs.statSync(full).isDirectory()) {
      addDir(full, key);
    } else {
      files[key] = fs.readFileSync(full).toString('base64');
    }
  }
}

addDir(WIZARD_DIST);

const entries = Object.entries(files)
  .map(([k, v]) => `  ${JSON.stringify(k)}: Buffer.from(\n    ${JSON.stringify(v)},\n    'base64'\n  ),`)
  .join('\n');

const output = `// AUTO-GENERATED by scripts/generate-wizard-bundle.mjs — DO NOT EDIT
// Rebuild with: npm run build:wizard && npm run generate-bundle
export const wizardFiles: Record<string, Buffer> = {
${entries}
};
`;

fs.writeFileSync(OUTPUT, output);
console.log(`[generate-wizard-bundle] Bundled ${Object.keys(files).length} files → src/wizard-bundle.ts`);
